import React from "react";
import "./HospitalListing.css";

const hospitals = [
  {
    name: "City Care Hospital",
    location: "Kathmandu",
    specialties: "Cardiology, Neurology, Pediatrics",
    contact: "01-5551234",
  },
  {
    name: "Green Valley Medical Center",
    location: "Pokhara",
    specialties: "Orthopedics, Dermatology, ENT",
    contact: "061-456789",
  },
  {
    name: "Himalayan Health Clinic",
    location: "Bhaktapur",
    specialties: "Internal Medicine, Urology",
    contact: "01-6677889",
  },
];

function HospitalListing() {
  return (
    <div className="container">
      <h1>Available Hospitals</h1>

      <div className="search-bar">
        <input type="text" placeholder="Search hospitals..." />
        <button>Search</button>
      </div>

      <div className="hospital-grid">
        {hospitals.map((hospital, index) => (
          <div className="card" key={index}>
            <h2>{hospital.name}</h2>
            <p>
              <strong>Location:</strong> {hospital.location}
            </p>
            <p>
              <strong>Specialties:</strong> {hospital.specialties}
            </p>
            <p>
              <strong>Contact:</strong> {hospital.contact}
            </p>
            <button className="view-btn">View Doctors</button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default HospitalListing;
